#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>

#define PAGE_SIZE 4096
#define PTE_VALID_MASK     0x0001
#define PTE_PROTECTION_MASK 0x0006
#define PTE_REFERENCED_MASK 0x0008
#define PTE_DIRTY_MASK      0x0010

// Page Table Entry structure
typedef struct {
    uint32_t frame_number : 20;  // Physical frame (4GB / 4KB = 2^20 frames)
    uint32_t valid        : 1;
    uint32_t prot_read    : 1;
    uint32_t prot_write   : 1;
    uint32_t prot_exec    : 1;
    uint32_t referenced   : 1;
    uint32_t dirty        : 1;
    uint32_t reserved     : 6;
} __attribute__((packed)) PTE;

// Simulated page table
PTE page_table[1048576];  // 2^20 entries for 4GB virtual space

uint32_t translate_address(uint32_t virtual_addr) {
    // Extract page number and offset
    uint32_t page_number = virtual_addr / PAGE_SIZE;
    uint32_t offset = virtual_addr % PAGE_SIZE;

    // Check valid bit
    if (!(page_table[page_number].valid)) {
        printf("Page fault! VPN: %u\n", page_number);
        return 0xFFFFFFFF;  // Indicate error
    }

    // Set referenced bit
    page_table[page_number].referenced = 1;

    // Get physical frame
    uint32_t frame = page_table[page_number].frame_number;

    // Construct physical address
    uint32_t physical_addr = (frame * PAGE_SIZE) + offset;

    return physical_addr;
}

int main() {
    // Initialize some entries
    page_table[0].frame_number = 100;
    page_table[0].valid = 1;
    page_table[0].prot_read = 1;
    page_table[0].prot_write = 1;

    // Test translation
    uint32_t va = 0x00001000;  // Page 1, offset 0x1000
    uint32_t pa = translate_address(va);

    printf("Virtual: 0x%08X -> Physical: 0x%08X\n", va, pa);

    return 0;
}
